FIXTURES.Card = (function Card() {
  var cardTemplate = document.getElementById('card-template');

  function createFixtureCard(fixture) {
    var cardEl = cardTemplate.content.cloneNode(true);
    cardEl.querySelector('.opponent').innerText = fixture.opponent;
    cardEl.querySelector('.competition').innerText = fixture.competition;
    cardEl.querySelector('.kickoff').innerText = fixture.kickoff;
    cardEl.querySelector('.crest').style['background-image'] = 'url(/assets/crests/' + fixture.badge + ')';
    return cardEl;
  }

  return {
    createFixtureCard: createFixtureCard
  }

}());
